def solve(prices: Array[Long], strategy: Array[Long], k: Long): Long = {
    val n = prices.length
    val kInt = k.toInt
    val halfK = kInt / 2

    // Calculate the original profit
    val originalProfit = (0 until n).map(i => strategy(i) * prices(i)).sum

    // Precompute the prefix sum of (strategy[i] * prices[i])
    val prefixSum = Array.ofDim[Long](n + 1)
    for (i <- 0 until n) {
        prefixSum(i + 1) = prefixSum(i) + strategy(i) * prices(i)
    }

    // Precompute the sum of prices for the first half (0) and second half (1) of the window
    val windowSum0 = Array.ofDim[Long](n)
    val windowSum1 = Array.ofDim[Long](n)

    // Compute sliding window sums for the first half (0) and second half (1)
    var sum0 = 0L
    var sum1 = 0L
    for (i <- 0 until kInt) {
        if (i < halfK) {
            sum0 += prices(i)
        } else {
            sum1 += prices(i)
        }
    }
    if (kInt <= n) {
        windowSum0(kInt - 1) = sum0
        windowSum1(kInt - 1) = sum1
    }

    for (i <- kInt until n) {
        sum0 = sum0 - prices(i - kInt) + prices(i - halfK)
        sum1 = sum1 - prices(i - halfK) + prices(i)
        windowSum0(i) = sum0
        windowSum1(i) = sum1
    }

    // Compute the maximum delta for each possible window
    var maxDelta = 0L
    for (i <- kInt - 1 until n) {
        val start = i - kInt + 1
        val end = i
        val original = prefixSum(end + 1) - prefixSum(start)
        val modified = 0L * sum0 + 1L * sum1
        val delta = modified - original
        if (delta > maxDelta) {
            maxDelta = delta
        }
        // Update sum0 and sum1 for the next window (if not last)
        if (i + 1 < n) {
            sum0 = sum0 - prices(start) + prices(start + halfK)
            sum1 = sum1 - prices(start + halfK) + prices(end + 1)
        }
    }

    originalProfit + maxDelta
}
